import * as Utilities from "lib/ie-utilities";

describe("IE utilities", () => {
  describe("isIE", () => {
    let userAgent;

    beforeEach(() => {
      userAgent = jest.spyOn(window.navigator, "userAgent", "get");
    });

    test.each`
      browser              | agent                                                                                                                                                      | expected
      ${"IE9"}             | ${"Mozilla/5.0(compatible; MSIE 9.0; Windows NT 6.1; Trident/5.0)"}                                                                                        | ${true}
      ${"IE10"}            | ${"Mozilla/5.0(compatible; MSIE 10.0; Windows NT 6.2; Trident/6.0)"}                                                                                       | ${true}
      ${"IE11"}            | ${"Mozilla/5.0 (Windows NT 10.0; WOW64; Trident/7.0; .NET4.0C; .NET4.0E; .NET CLR 2.0.50727; .NET CLR 3.0.30729; .NET CLR 3.5.30729; rv:11.0) like Gecko"} | ${true}
      ${"Edge"}            | ${"Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/52.0.2743.116 Safari/537.36 Edge/15.15063"}                     | ${false}
      ${"Chrome"}          | ${"Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/73.0.3672.0 Safari/537.36"}                                     | ${false}
      ${"Mozilla"}         | ${"Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:56.0) Gecko/20100101 Firefox/56.0"}                                                                        | ${false}
      ${"Chrome Edge Mac"} | ${"Mozilla/5.0 (Macintosh; Intel Mac OS X 10_15_3) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/82.0.4056.0 Safari/537.36 Edg/82.0.432.3"}                | ${false}
    `("returns $expected when browser is $browser", ({ agent, expected }) => {
      userAgent.mockReturnValue(agent);

      expect(Utilities.isIE()).toBe(expected);
    });
  });
});
